+    if (var_type == .unknown) {
+        if (is_mutated) {
+            try self.emit(": *@TypeOf(");
+        } else {
+            try self.emit(": @TypeOf(");
+        }
+        if (self.var_renames.get(var_name)) |renamed| {
+            try self.emit(renamed);
+        } else {
+            try zig_keywords.writeEscapedIdent(self.output.writer(self.allocator), var_name);
+        }
+        try self.emit(")");
+        return;
+    }
